import{_ as t,o as a,c as r,ag as i}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Tableau de bord","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/dashboard.md","filePath":"fr/features/dashboard.md"}'),s={name:"fr/features/dashboard.md"};function l(o,e,d,n,u,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="tableau-de-bord" tabindex="-1">Tableau de bord <a class="header-anchor" href="#tableau-de-bord" aria-label="Permalink to &quot;Tableau de bord&quot;">​</a></h1><p>Le tableau de bord est votre page d&#39;accueil dans MyCompanyDesk. Il vous offre une vue d&#39;ensemble de vos finances, alertes et actions rapides.</p><h2 id="profils-de-tableau-de-bord" tabindex="-1">Profils de tableau de bord <a class="header-anchor" href="#profils-de-tableau-de-bord" aria-label="Permalink to &quot;Profils de tableau de bord&quot;">​</a></h2><p>MyCompanyDesk propose des profils de tableau de bord bases sur les roles, qui adaptent les indicateurs et les cartes affiches a vos besoins :</p><table tabindex="0"><thead><tr><th>Profil</th><th>Orientation</th></tr></thead><tbody><tr><td><strong>Proprietaire / Directeur</strong></td><td>Tresorerie, rentabilite, vue d&#39;ensemble</td></tr><tr><td><strong>Comptable / Expert-comptable</strong></td><td>TVA, conformite, pistes d&#39;audit, verrouillage des periodes</td></tr><tr><td><strong>CC (Facturation)</strong></td><td>Indicateurs de facturation, paiements en attente</td></tr><tr><td><strong>CF (Achats)</strong></td><td>Suivi des depenses, gestion des fournisseurs</td></tr><tr><td><strong>Freelance</strong></td><td>Facturation et suivi des revenus simplifie</td></tr><tr><td><strong>Conformite TVA</strong></td><td>Calculs TVA, echeances, declarations</td></tr><tr><td><strong>Base sur les projets</strong></td><td>Rentabilite des projets, suivi du temps</td></tr><tr><td><strong>Croissance / Operations</strong></td><td>Tendances de revenus, acquisition de clients</td></tr></tbody></table><h3 id="changer-de-profil" tabindex="-1">Changer de profil <a class="header-anchor" href="#changer-de-profil" aria-label="Permalink to &quot;Changer de profil&quot;">​</a></h3><ol><li>Ouvrez le tableau de bord</li><li>Cliquez sur le selecteur de profil en haut</li><li>Choisissez le profil qui correspond le mieux a votre role</li></ol><p>Chaque profil affiche differentes cartes d&#39;indicateurs, alertes et actions rapides pertinentes pour ce role.</p><h2 id="sections-du-tableau-de-bord" tabindex="-1">Sections du tableau de bord <a class="header-anchor" href="#sections-du-tableau-de-bord" aria-label="Permalink to &quot;Sections du tableau de bord&quot;">​</a></h2><h3 id="alertes" tabindex="-1">Alertes <a class="header-anchor" href="#alertes" aria-label="Permalink to &quot;Alertes&quot;">​</a></h3><p>Elements critiques necessitant votre attention :</p><ul><li>Factures en retard</li><li>Echeances TVA a venir</li><li>Contrats arrivant a expiration</li><li>Alertes de tresorerie faible</li></ul><h3 id="indicateurs-cles" tabindex="-1">Indicateurs cles <a class="header-anchor" href="#indicateurs-cles" aria-label="Permalink to &quot;Indicateurs cles&quot;">​</a></h3><p>Cartes de synthese affichant vos chiffres les plus importants :</p><ul><li>Chiffre d&#39;affaires total (periode en cours)</li><li>Factures en attente</li><li>Total des depenses</li><li>Benefice / perte net(te)</li><li>Devis ouverts</li></ul><h3 id="selection-de-la-periode" tabindex="-1">Selection de la periode <a class="header-anchor" href="#selection-de-la-periode" aria-label="Permalink to &quot;Selection de la periode&quot;">​</a></h3><p>Basculez entre differentes periodes pour consulter vos indicateurs :</p><ul><li>Cette semaine / ce mois / ce trimestre / cette annee</li><li>Plage de dates personnalisee</li><li>Comparaison avec les periodes precedentes</li></ul><h3 id="actions-rapides" tabindex="-1">Actions rapides <a class="header-anchor" href="#actions-rapides" aria-label="Permalink to &quot;Actions rapides&quot;">​</a></h3><p>Raccourcis vers vos taches les plus courantes :</p><ul><li>Creer une nouvelle facture</li><li>Ajouter une depense</li><li>Enregistrer une entree de temps</li><li>Consulter les rapports</li></ul><h3 id="activite-recente" tabindex="-1">Activite recente <a class="header-anchor" href="#activite-recente" aria-label="Permalink to &quot;Activite recente&quot;">​</a></h3><p>Un fil d&#39;evenements recents dans votre espace de travail :</p><ul><li>Factures envoyees et payees</li><li>Depenses ajoutees</li><li>Clients crees</li><li>Actions des membres de l&#39;equipe</li></ul><h2 id="carte-d-accueil" tabindex="-1">Carte d&#39;accueil <a class="header-anchor" href="#carte-d-accueil" aria-label="Permalink to &quot;Carte d&#39;accueil&quot;">​</a></h2><p>Les nouveaux utilisateurs voient une carte d&#39;accueil qui les guide dans la configuration initiale :</p><ol><li>Configurer les informations de l&#39;entreprise</li><li>Ajouter un premier client</li><li>Creer une premiere facture</li></ol><p>La carte suit votre progression et disparait une fois terminee (ou lorsqu&#39;elle est fermee manuellement).</p>',28)])])}const b=t(s,[["render",l]]);export{h as __pageData,b as default};
